def append_batch():
    if os.path.exists(EMAILS_JSON):
        try:
            with open(EMAILS_JSON, 'r', encoding='utf-8') as f:
                data = json.load(f)
        except Exception:
            data = {}
    else:
        data = {}
        
    for item in batch_data:
        row_idx = str(item['row_index'])
        data[row_idx] = {
            'day1_title': item['day1_title'],
            'day1_content': item['day1_content'],
            'day7_title': item['day7_title'],
            'day7_content': item['day7_content'],
            'day14_title': item['day14_title'],
            'day14_content': item['day14_content'],
            'day30_title': item['day30_title'],
            'day30_content': item['day30_content'],
            'day60_title': item['day60_title'],
            'day60_content': item['day60_content']
        }
        
    os.makedirs(os.path.dirname(EMAILS_JSON), exist_ok=True)
    with open(EMAILS_JSON, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"Successfully saved {len(batch_data)} companies. Total in JSON: {len(data)}")

if __name__ == '__main__':
    append_batch()
